const employeeData = items[0].json;
const formData = $('On form submission').first().json;

const start = DateTime.fromISO(formData["Tanggal Mulai"]);
const end = DateTime.fromISO(formData["Tanggal Selesai"]);

const durationInDays = end.diff(start, 'days').days + 1;

const currentBalance = parseInt(employeeData["Saldo_Cuti"]);
const hasEnoughBalance = currentBalance >= durationInDays;

const uniqueId = 'REQ-' + Date.now();

return [
  {
    json: {
      ...employeeData,
      ...formData,
      durationRequested: durationInDays,
      isApprovedSystem: hasEnoughBalance,
      message: hasEnoughBalance ? "Saldo Cukup" : "Saldo Tidak Cukup",
      requestId: uniqueId,
      status: hasEnoughBalance ? "Pending Approval" : "Rejected - Insufficient Balance"
    }
  }
];

